<?php include __DIR__.'/_init.php'; if($_SERVER['REQUEST_METHOD']==='POST'){if(!verify_csrf($_POST['csrf_token']??''))die('CSRF');$db->prepare('INSERT INTO live_classes(course_id,title,meeting_link,start_time,end_time) VALUES(?,?,?,?,?)')->execute([(int)$_POST['course_id'],sanitize($_POST['title']),sanitize($_POST['meeting_link']),$_POST['start_time'],$_POST['end_time']]);redirect('/admin/live-classes.php');}
$courses=$db->query('SELECT id,title FROM courses')->fetchAll();$rows=$db->query('SELECT l.*,c.title course_title FROM live_classes l JOIN courses c ON c.id=l.course_id ORDER BY start_time DESC')->fetchAll();?><h2>Live Classes</h2><form method="post"><input type="hidden" name="csrf_token" value="<?=csrf_token()?>"><select name="course_id"><?php foreach($courses as $c):?><option value="<?=$c['id']?>"><?=e($c['title'])?></option><?php endforeach;?></select><input name="title" placeholder="Session title"><input name="meeting_link" placeholder="Link"><input type="datetime-local" name="start_time"><input type="datetime-local" name="end_time"><button>Save</button></form><?php foreach($rows as $r):?><div><?=e($r['course_title'])?> - <?=e($r['title'])?> - <?=e($r['start_time'])?></div><?php endforeach;?>
